 40→    companion object {
 41→        /**
 42→         * If the number of addresses exceeds this value the addresses aren't
 43→         * resolved to the names of Android contacts.
 44→         *
 45→         * TODO: This number was chosen arbitrarily and should be determined by performance tests.
 46→         *
 47→         * @see .toFriendly
 48→         */
 49→        private const val TOO_MANY_ADDRESSES = 50
 50→        private val SPOOF_ADDRESS_PATTERN = Pattern.compile("[^(]@")
 51→
 52→        /**
 53→         * Returns the name of the contact this email address belongs to if
 54→         * the [contacts][Contacts] parameter is not `null` and a
 55→         * contact is found. Otherwise the personal portion of the [Address]
 56→         * is returned. If that isn't available either, the email address is
 57→         * returned.
 58→         *
 59→         * @param address An [com.fsck.k9.mail.Address]
 60→         * @param contacts A [Contacts] instance or `null`.
 61→         * @return A "friendly" name for this [Address].
 62→         */
 63→        fun toFriendly(address: Address, contactRepository: ContactRepository?): CharSequence {
 64→            return toFriendly(
 65→                address,
 66→                contactRepository,
 67→                isShowCorrespondentNames,
 68→                isChangeContactNameColor,
 69→                contactNameColor,
 70→            )
 71→        }
 72→
 73→        fun toFriendly(addresses: Array<Address>?, contactRepository: ContactRepository?): CharSequence? {
 74→            var repository = contactRepository
 75→            if (addresses == null) {
 76→                return null
 77→            }
 78→            if (addresses.size >= TOO_MANY_ADDRESSES) {
 79→                // Don't look up contacts if the number of addresses is very high.
 80→                repository = null
 81→            }
 82→            val stringBuilder = SpannableStringBuilder()
 83→            for (i in addresses.indices) {
 84→                stringBuilder.append(toFriendly(addresses[i], repository))
 85→                if (i < addresses.size - 1) {
 86→                    stringBuilder.append(',')
 87→                }
 88→            }
 89→            return stringBuilder
 90→        }
 91→
 92→        /* package, for testing */
 93→        @JvmStatic
 94→        fun toFriendly(
 95→            address: Address,
 96→            contactRepository: ContactRepository?,
 97→            showCorrespondentNames: Boolean,
 98→            changeContactNameColor: Boolean,
 99→            contactNameColor: Int,
100→        ): CharSequence {
101→            if (!showCorrespondentNames) {
102→                return address.address
103→            } else if (contactRepository != null) {
104→                val name = contactRepository.getContactName(address)
105→                if (name != null) {
106→                    return if (changeContactNameColor) {
107→                        val coloredName = SpannableString(name)
108→                        coloredName.setSpan(
109→                            ForegroundColorSpan(contactNameColor),
110→                            0,
111→                            coloredName.length,
112→                            Spannable.SPAN_EXCLUSIVE_EXCLUSIVE,
113→                        )
114→                        coloredName
115→                    } else {
116→                        name
117→                    }
118→                }
119→            }
120→            return if (!TextUtils.isEmpty(address.personal) && !isSpoofAddress(address.personal)) {
121→                address.personal
122→            } else {
123→                address.address
124→            }
125→        }
126→
127→        private fun ContactRepository.getContactName(address: Address): String? {
128→            return address.address.toEmailAddressOrNull()?.let { emailAddress ->
129→                getContactFor(emailAddress)?.name
130→            }
131→        }
132→
133→        private fun isSpoofAddress(displayName: String): Boolean {
134→            return displayName.contains("@") && SPOOF_ADDRESS_PATTERN.matcher(displayName).find()
135→        }
136→    }
137→}
