 30→class Preferences internal constructor(
 31→    private val storagePersister: StoragePersister,
 32→    private val localStoreProvider: LocalStoreProvider,
 33→    private val accountPreferenceSerializer: AccountPreferenceSerializer,
 34→    private val backgroundDispatcher: CoroutineDispatcher = Dispatchers.IO,
 35→) : AccountManager {
 36→    private val accountLock = Any()
 37→    private val storageLock = Any()
 38→
 39→    @GuardedBy("accountLock")
 40→    private var accountsMap: MutableMap<String, Account>? = null
 41→
 42→    @GuardedBy("accountLock")
 43→    private var accountsInOrder = mutableListOf<Account>()
 44→
 45→    @GuardedBy("accountLock")
 46→    private var newAccount: Account? = null
 47→    private val accountsChangeListeners = CopyOnWriteArraySet<AccountsChangeListener>()
 48→    private val accountRemovedListeners = CopyOnWriteArraySet<AccountRemovedListener>()
 49→
 50→    @GuardedBy("storageLock")
 51→    private var currentStorage: Storage? = null
 52→
 53→    val storage: Storage
 54→        get() = synchronized(storageLock) {
 55→            currentStorage ?: storagePersister.loadValues().also { newStorage ->
 56→                currentStorage = newStorage
 57→            }
 58→        }
 59→
 60→    fun createStorageEditor(): StorageEditor {
 61→        return storagePersister.createStorageEditor { updater ->
 62→            synchronized(storageLock) {
 63→                currentStorage = updater(storage)
 64→            }
 65→        }
 66→    }
 67→
 68→    @RestrictTo(RestrictTo.Scope.TESTS)
 69→    fun clearAccounts() {
 70→        synchronized(accountLock) {
 71→            accountsMap = HashMap()
 72→            accountsInOrder = LinkedList()
 73→        }
 74→    }
 75→
 76→    fun loadAccounts() {
 77→        synchronized(accountLock) {
 78→            val accounts = mutableMapOf<String, Account>()
 79→            val accountsInOrder = mutableListOf<Account>()
 80→
 81→            val accountUuids = storage.getString("accountUuids", null)
 82→            if (!accountUuids.isNullOrEmpty()) {
 83→                accountUuids.split(",").forEach { uuid ->
 84→                    val newAccount = Account(uuid, K9::isSensitiveDebugLoggingEnabled)
 85→                    accountPreferenceSerializer.loadAccount(newAccount, storage)
 86→
 87→                    accounts[uuid] = newAccount
 88→                    accountsInOrder.add(newAccount)
 89→                }
 90→            }
 91→
 92→            newAccount?.takeIf { it.accountNumber != -1 }?.let { newAccount ->
 93→                accounts[newAccount.uuid] = newAccount
 94→                if (newAccount !in accountsInOrder) {
 95→                    accountsInOrder.add(newAccount)
 96→                }
 97→                this.newAccount = null
 98→            }
 99→
100→            this.accountsMap = accounts
101→            this.accountsInOrder = accountsInOrder
102→        }
103→    }
104→
105→    override fun getAccounts(): List<Account> {
106→        synchronized(accountLock) {
107→            if (accountsMap == null) {
108→                loadAccounts()
109→            }
110→
111→            return accountsInOrder.toList()
112→        }
113→    }
114→
115→    private val completeAccounts: List<Account>
116→        get() = getAccounts().filter { it.isFinishedSetup }
117→
118→    override fun getAccount(accountUuid: String): Account? {
119→        synchronized(accountLock) {
120→            if (accountsMap == null) {
121→                loadAccounts()
122→            }
123→
124→            return accountsMap!![accountUuid]
125→        }
126→    }
127→
128→    override fun getAccountFlow(accountUuid: String): Flow<Account> {
129→        return callbackFlow {
130→            val initialAccount = getAccount(accountUuid)
131→            if (initialAccount == null) {
132→                close()
133→                return@callbackFlow
134→            }
135→
136→            send(initialAccount)
137→
138→            val listener = AccountsChangeListener {
139→                val account = getAccount(accountUuid)
140→                if (account != null) {
141→                    trySendBlocking(account)
142→                } else {
143→                    close()
144→                }
145→            }
146→            addOnAccountsChangeListener(listener)
147→
148→            awaitClose {
149→                removeOnAccountsChangeListener(listener)
150→            }
151→        }.buffer(capacity = Channel.CONFLATED)
152→            .flowOn(backgroundDispatcher)
153→    }
154→
155→    @OptIn(ExperimentalCoroutinesApi::class)
156→    override fun getAccountsFlow(): Flow<List<Account>> {
157→        return callbackFlow {
158→            send(completeAccounts)
159→
160→            val listener = AccountsChangeListener {
161→                trySendBlocking(completeAccounts)
162→            }
163→            addOnAccountsChangeListener(listener)
164→
165→            awaitClose {
166→                removeOnAccountsChangeListener(listener)
167→            }
168→        }.buffer(capacity = Channel.CONFLATED)
169→            .flowOn(backgroundDispatcher)
170→    }
171→
172→    fun newAccount(): Account {
173→        val accountUuid = UUID.randomUUID().toString()
174→        return newAccount(accountUuid)
175→    }
176→
177→    fun newAccount(accountUuid: String): Account {
178→        val account = Account(accountUuid, K9::isSensitiveDebugLoggingEnabled)
179→        accountPreferenceSerializer.loadDefaults(account)
180→
181→        synchronized(accountLock) {
182→            newAccount = account
183→            accountsMap!![account.uuid] = account
184→            accountsInOrder.add(account)
185→        }
186→
187→        return account
188→    }
189→
190→    fun deleteAccount(account: Account) {
191→        synchronized(accountLock) {
192→            accountsMap?.remove(account.uuid)
193→            accountsInOrder.remove(account)
194→
195→            val storageEditor = createStorageEditor()
196→            accountPreferenceSerializer.delete(storageEditor, storage, account)
197→            storageEditor.commit()
198→
199→            if (account === newAccount) {
200→                newAccount = null
201→            }
202→        }
203→
204→        notifyAccountRemovedListeners(account)
205→        notifyAccountsChangeListeners()
206→    }
207→
208→    val defaultAccount: Account?
209→        get() = getAccounts().firstOrNull()
210→
211→    override fun saveAccount(account: Account) {
212→        ensureAssignedAccountNumber(account)
213→        processChangedValues(account)
214→
215→        synchronized(accountLock) {
216→            val editor = createStorageEditor()
217→            accountPreferenceSerializer.save(editor, storage, account)
218→            editor.commit()
219→        }
220→
221→        notifyAccountsChangeListeners()
222→    }
223→
224→    private fun ensureAssignedAccountNumber(account: Account) {
225→        if (account.accountNumber != Account.UNASSIGNED_ACCOUNT_NUMBER) return
226→
227→        account.accountNumber = generateAccountNumber()
228→    }
229→
230→    private fun processChangedValues(account: Account) {
231→        if (account.isChangedVisibleLimits) {
232→            try {
233→                localStoreProvider.getInstance(account).resetVisibleLimits(account.displayCount)
234→            } catch (e: MessagingException) {
235→                Timber.e(e, "Failed to load LocalStore!")
236→            }
237→        }
238→        account.resetChangeMarkers()
239→    }
240→
241→    fun generateAccountNumber(): Int {
242→        val accountNumbers = getAccounts().map { it.accountNumber }
243→        return findNewAccountNumber(accountNumbers)
244→    }
245→
246→    private fun findNewAccountNumber(accountNumbers: List<Int>): Int {
247→        var newAccountNumber = -1
248→        for (accountNumber in accountNumbers.sorted()) {
249→            if (accountNumber > newAccountNumber + 1) {
250→                break
251→            }
252→            newAccountNumber = accountNumber
253→        }
254→        newAccountNumber++
255→
256→        return newAccountNumber
257→    }
258→
259→    override fun moveAccount(account: Account, newPosition: Int) {
260→        synchronized(accountLock) {
261→            val storageEditor = createStorageEditor()
262→            accountPreferenceSerializer.move(storageEditor, account, storage, newPosition)
263→            storageEditor.commit()
264→
265→            loadAccounts()
266→        }
267→
268→        notifyAccountsChangeListeners()
269→    }
270→
271→    private fun notifyAccountsChangeListeners() {
272→        for (listener in accountsChangeListeners) {
273→            listener.onAccountsChanged()
274→        }
275→    }
276→
277→    override fun addOnAccountsChangeListener(accountsChangeListener: AccountsChangeListener) {
278→        accountsChangeListeners.add(accountsChangeListener)
279→    }
280→
281→    override fun removeOnAccountsChangeListener(accountsChangeListener: AccountsChangeListener) {
282→        accountsChangeListeners.remove(accountsChangeListener)
283→    }
284→
285→    private fun notifyAccountRemovedListeners(account: Account) {
286→        for (listener in accountRemovedListeners) {
287→            listener.onAccountRemoved(account)
288→        }
289→    }
290→
291→    override fun addAccountRemovedListener(listener: AccountRemovedListener) {
292→        accountRemovedListeners.add(listener)
293→    }
294→
295→    fun removeAccountRemovedListener(listener: AccountRemovedListener) {
296→        accountRemovedListeners.remove(listener)
297→    }
298→
299→    companion object {
300→        @JvmStatic
301→        fun getPreferences(): Preferences {
302→            return DI.get()
303→        }
304→    }
305→}
