 58→    private fun updateSpecialFolder(type: FolderType, folders: List<RemoteFolder>) {
 59→        val importedServerId = getImportedSpecialFolderServerId(type)
 60→        if (importedServerId != null) {
 61→            val folderId = folders.firstOrNull { it.serverId == importedServerId }?.id
 62→            if (folderId != null) {
 63→                setSpecialFolder(type, folderId, getSpecialFolderSelection(type))
