import app.k9mail.legacy.account.Account
import app.k9mail.legacy.account.AccountManager
import assertk.assertThat
import assertk.assertions.isFalse
import assertk.assertions.isTrue
import com.fsck.k9.K9
import org.junit.After
import org.junit.Before
import org.junit.Test
import org.mockito.kotlin.doReturn
import org.mockito.kotlin.mock

class UnifiedInboxConfiguratorTest {

    @Before
    fun setUp() {
        K9.isShowUnifiedInbox = false
    }

    @After
    fun tearDown() {
        K9.isShowUnifiedInbox = false
    }

    @Test
    fun `configureUnifiedInbox with single account should not enable unified inbox`() {
        val accountManager = createAccountManagerWithAccounts(1)
        val configurator = UnifiedInboxConfigurator(accountManager)

        configurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    @Test
    fun `configureUnifiedInbox with two accounts should enable unified inbox`() {
        val accountManager = createAccountManagerWithAccounts(2)
        val configurator = UnifiedInboxConfigurator(accountManager)

        configurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isTrue()
    }

    @Test
    fun `configureUnifiedInbox with three accounts should not change unified inbox setting`() {
        val accountManager = createAccountManagerWithAccounts(3)
        val configurator = UnifiedInboxConfigurator(accountManager)

        // Initially disabled
        K9.isShowUnifiedInbox = false
        configurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    @Test
    fun `configureUnifiedInbox with three accounts preserves enabled unified inbox setting`() {
        val accountManager = createAccountManagerWithAccounts(3)
        val configurator = UnifiedInboxConfigurator(accountManager)

        // Initially enabled (user preference)
        K9.isShowUnifiedInbox = true
        configurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isTrue()
    }

    @Test
    fun `configureUnifiedInbox with zero accounts should not enable unified inbox`() {
        val accountManager = createAccountManagerWithAccounts(0)
        val configurator = UnifiedInboxConfigurator(accountManager)

        configurator.configureUnifiedInbox()

        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    private fun createAccountManagerWithAccounts(count: Int): AccountManager {
        val accounts = (1..count).map { createMockAccount("uuid-$it") }
        return mock {
            on { getAccounts() } doReturn accounts
        }
    }

    private fun createMockAccount(uuid: String): Account {
        return mock {
            on { this.uuid } doReturn uuid
        }
    }
}
"}

