271→    /**
272→     * Quote a string, if necessary, based upon the definition of an "atom," as defined by RFC2822
273→     * (http://tools.ietf.org/html/rfc2822#section-3.2.4). Strings that consist purely of atoms are
274→     * left unquoted; anything else is returned as a quoted string.
275→     * @param text String to quote.
276→     * @return Possibly quoted string.
277→     */
278→    public static String quoteAtoms(final String text) {
279→        if (ATOM.matcher(text).matches()) {
280→            return text;
281→        } else {
282→            return quoteString(text);
283→        }
284→    }
