286→    /**
287→     * Ensures that the given string starts and ends with the double quote character.
288→     * The string is not modified in any way except to add the double quote character to start
289→     * and end if it's not already there.
290→     * sample -> "sample"
291→     * "sample" -> "sample"
292→     * ""sample"" -> ""sample""
293→     * "sample"" -> "sample"
294→     * sa"mp"le -> "sa"mp"le"
295→     * "sa"mp"le" -> "sa"mp"le"
296→     * (empty string) -> ""
297→     * " -> """
298→     * @param s
299→     * @return
300→     */
301→    @VisibleForTesting
302→    static String quoteString(String s) {
303→        if (s == null) {
304→            return null;
305→        }
306→        if (!s.matches("^\".*\"$")) {
307→            return "\"" + s + "\"";
308→        } else {
309→            return s;
310→        }
