    @Throws(NonAsciiEmailAddressException::class)
    fun parse(input: String): List<Address> {
        return Address.parseUnencoded(input)
            .mapNotNull { address ->
                when {
                    address.isIncomplete() -> null
                    address.hasInvalidHostname() -> null
                    address.isNonAsciiAddress() -> throw NonAsciiEmailAddressException(address.address)
                    else -> Address.parse(address.toEncodedString()).firstOrNull()
                }
            }
    }

    private fun Address.isIncomplete() = hostname.isNullOrBlank()

    /**
     * Check if the hostname contains invalid characters.
     * According to RFC 5321, a valid domain hostname should only contain letters, digits, hyphens, and periods.
     */
    private fun Address.hasInvalidHostname(): Boolean {
        val hostname = this.hostname ?: return false
        return !hostname.matches(VALID_HOSTNAME_REGEX)
    }

    private fun Address.isNonAsciiAddress() = !CharsetUtil.isASCII(address)

    companion object {
        // Valid hostname: letters, digits, hyphens, and periods only
        // Each label (part between dots) should start and end with alphanumeric characters
        private val VALID_HOSTNAME_REGEX = Regex("^[a-zA-Z0-9]([a-zA-Z0-9-]*[a-zA-Z0-9])?(\\.[a-zA-Z0-9]([a-zA-Z0-9-]*[a-zA-Z0-9])?)*$")
    }
}"}

